---
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import '../styles/global.css';
import type { Locale } from '../i18n';
import {
  AUTHOR,
  DEFAULT_OG_IMAGE,
  GOOGLE_SITE_VERIFICATION,
  absoluteUrl,
} from '../site';

interface Props {
  title: string;
  description: string;
  locale: Locale;
  alternate: string;
  image?: string;
  section?: 'hub' | 'esaa';
  ogType?: 'website' | 'article';
  publishedTime?: Date;
  modifiedTime?: Date;
  tags?: string[];
  jsonLd?: Record<string, unknown> | Record<string, unknown>[];
}

const {
  title,
  description,
  locale,
  alternate,
  image = DEFAULT_OG_IMAGE,
  section = 'hub',
  ogType = 'website',
  publishedTime,
  modifiedTime,
  tags = [],
  jsonLd,
} = Astro.props;

const canonical = new URL(Astro.url.pathname, Astro.site);
const alternateUrl = new URL(alternate, Astro.site);
const ogImage = absoluteUrl(image, Astro.site?.href ?? undefined);
const jsonLdBlocks = jsonLd
  ? Array.isArray(jsonLd)
    ? jsonLd
    : [jsonLd]
  : [];
---
<!doctype html>
<html lang={locale === 'pt' ? 'pt-BR' : 'en'}>
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width" />
    <meta name="description" content={description} />
    <meta name="author" content={AUTHOR.name} />
    <meta name="theme-color" content="#f5f1e8" />
    {GOOGLE_SITE_VERIFICATION && (
      <meta name="google-site-verification" content={GOOGLE_SITE_VERIFICATION} />
    )}
    <link rel="canonical" href={canonical} />
    <link rel="alternate" hreflang={locale === 'pt' ? 'en' : 'pt-BR'} href={alternateUrl} />
    <link rel="alternate" hreflang={locale === 'pt' ? 'pt-BR' : 'en'} href={canonical} />
    <link rel="alternate" hreflang="x-default" href={locale === 'pt' ? canonical : alternateUrl} />
    <link rel="icon" href="/favicon.svg" type="image/svg+xml" />
    <meta property="og:type" content={ogType} />
    <meta property="og:site_name" content={AUTHOR.name} />
    <meta property="og:title" content={title} />
    <meta property="og:description" content={description} />
    <meta property="og:url" content={canonical} />
    <meta property="og:image" content={ogImage} />
    <meta property="og:locale" content={locale === 'pt' ? 'pt_BR' : 'en_US'} />
    {ogType === 'article' && publishedTime && (
      <meta property="article:published_time" content={publishedTime.toISOString()} />
    )}
    {ogType === 'article' && modifiedTime && (
      <meta property="article:modified_time" content={modifiedTime.toISOString()} />
    )}
    {ogType === 'article' && (
      <meta property="article:author" content={AUTHOR.name} />
    )}
    {ogType === 'article' && tags.map((tag) => (
      <meta property="article:tag" content={tag} />
    ))}
    <meta name="twitter:card" content="summary_large_image" />
    <meta name="twitter:title" content={title} />
    <meta name="twitter:description" content={description} />
    <meta name="twitter:image" content={ogImage} />
    <title>{title}</title>
    {jsonLdBlocks.map((block) => (
      <script is:inline type="application/ld+json" set:html={JSON.stringify(block)} />
    ))}
    <script is:inline>
      const saved = localStorage.getItem('theme');
      document.documentElement.dataset.theme = saved === 'dark' ? 'dark' : 'light';
    </script>
  </head>
  <body>
    <Header locale={locale} alternate={alternate} section={section} />
    <main id="conteudo"><slot /></main>
    <Footer locale={locale} />
    <script is:inline>
      document.querySelector('.theme-toggle')?.addEventListener('click', () => {
        const next = document.documentElement.dataset.theme === 'dark' ? 'light' : 'dark';
        document.documentElement.dataset.theme = next;
        localStorage.setItem('theme', next);
      });
    </script>
  </body>
</html>
